import React, { useContext, useEffect, useRef, useState } from 'react';

import Button from '@components/ui/Button';
import Loading from '@components/ui/Loading';
import EmptyGfx from '@appSharedComponents/EmptyGfx';
import { ToastNotificationContext } from '@providers/ToastNotification';
// import { UserContext } from '@providers/User';
import { AngelOneMasterDataContext } from '@angelOneProviders/AngelOneMasterData';

import * as styles from './searchResults.module.css';

//======================+
//		TYPE-DEFS		|
//======================+
/**
 * AngelOne Instrument data
 * @typedef {import('@angelOneProviders/AngelOneMasterData').Instrument} Instrument
 */

/**
 * Displays instrument search results
 * @param {Object} props React prop passed to this component
 * @param {string} props.searchQuery Search query
 * @param {()=>{}} props.cancelSearch Callback function to execute in order to cancel search and go back
 * @param {([]:Instrument)=>Promise<boolean>} props.addToWatchlist Callback function to execute in order to add selected Instruments to watchlist
 * @param {Instrument[]} props.watchlistInstrumentsAry Instruments already in the watchlist (Useful to disallow adding more than the limit or avoid duplicate entries)
 * @param {number} [props.maxNumInstrumentsPerWatchlist=10] Max number of instruments allowed in currently selected watchlist
 */
export default function AngelOne_MarketWatch_SearchResults({
	searchQuery,
	cancelSearch,
	addToWatchlist,
	watchlistInstrumentsAry,
	maxNumInstrumentsPerWatchlist,
}) {
	const [selectedExchange, setSelectedExchange] = useState('NSE');
	const [isSearchWip, setIsSearchWip] = useState(false);
	const [searchResults, setSearchResults] = useState(/** @type {Instrument[]} */ ([]));
	const [selectedInstrumentsObj, setSelectedInstrumentsObj] = useState(/** @type {Object.<number, Instrument>}*/ ({}));
	const [isAddingOpWip, setIsAddingOpWip] = useState(false);

	const { notify } = useContext(ToastNotificationContext);
	// const { checkIfPlanActive } = useContext(UserContext);
	const { searchInstruments } = useContext(AngelOneMasterDataContext);

	const searchOpDelayTimeout = useRef(null);

	/**
	 * Toggles instrumnet selection
	 * @param {Instrument} instrument Instrument object
	 */
	const toggleInstrumentSelection = (instrument) => {
		// console.log('toggleInstrumentSelection() --> instrument', instrument);
		const clonedObj = { ...selectedInstrumentsObj }; //Object.assign({}, selectedInstrumentsObj)
		if (Object.prototype.hasOwnProperty.call(clonedObj, instrument.token)) {
			// console.log('Deleting from state object');
			delete clonedObj[instrument.token];
		} else {
			// console.log('Adding to state object');

			//here check if limit reached for max number of instruments allowed in watchlist it is being added to
			if (!watchlistInstrumentsAry || !Array.isArray(watchlistInstrumentsAry)) watchlistInstrumentsAry = [];
			if (watchlistInstrumentsAry.length < maxNumInstrumentsPerWatchlist) {
				clonedObj[instrument.token] = instrument;
			} else {
				notify('No more instruments can be added to this watchlist');
				return;
			}

			//here check if this instrument already exists in watchlist it is being added to
			const exists = watchlistInstrumentsAry.some(
				(existingInstrument) => existingInstrument.symbol === instrument.symbol && existingInstrument.exch_seg === instrument.exch_seg,
			);
			if (exists) {
				notify(instrument.symbol + ' instrument already exists in the watchlist');
				return;
			}
		}
		setSelectedInstrumentsObj(clonedObj);
	};

	useEffect(() => {
		if (searchQuery.trim() === '') return;

		//start search
		setIsSearchWip(true);
		//use setTimeout and clearTimeout to pause a bit before searching while the user is typing	//it's called debouncing
		clearTimeout(searchOpDelayTimeout.current);
		searchOpDelayTimeout.current = setTimeout(() => {
			(async () => {
				const searchRes = await searchInstruments(selectedExchange, searchQuery, 20);
				setIsSearchWip(false);
				if (!searchRes) {
					//console.log('No items found');
					notify('No Instruments found under ' + selectedExchange, 'alert');
					return false;
				}
				// console.log('searchRes:', searchRes);
				if (Array.isArray(searchRes)) {
					setSelectedInstrumentsObj({}); //empty the selected instruments bin since the search results have changed
					setSearchResults(searchRes);
				}
			})();
		}, 1000);

		// return () => {};	//cleanup if any
	}, [searchQuery, selectedExchange]); //runs on mount and then when either 'searchQuery' or 'selectedExchange' changes

	if (searchQuery.trim() === '') return null; //we wouldn't reach this since if this condition is met, this component won't be rendered in the first place

	return (
		<>
			<div className={styles.searchExchangeRadioC}>
				{['NSE', 'BSE', 'NFO', 'CDS', 'MCX'].map((exchange, i) => (
					<button
						key={exchange}
						onClick={() => {
							setSelectedExchange(exchange);
						}}
						className={selectedExchange === exchange ? styles.selected : null}
						// https://www.30secondsofcode.org/react/s/conditional-classname/
					>
						{exchange}
					</button>
				))}
			</div>
			{searchResults.length < 1 && !isSearchWip ? (
				// <div className={styles.notFoundC}>No Instruments Found listed under {selectedExchange} exchange for your query</div>
				<EmptyGfx icon="search" note={`No instruments found under ${selectedExchange} exchange for your query`} />
			) : (
				<ul className={styles.searchListUl}>
					{searchResults.map((instrument, i) => {
						const isSelected = Object.prototype.hasOwnProperty.call(selectedInstrumentsObj, instrument.token);
						return (
							<li key={`${instrument.token}${i}${isSelected ? 'y' : 'n'}`}>
								{/* in the key, also specify whether selected or not, thus react shall optimize during rerendering if item is added in/removed from selection bin */}
								<button
									onClick={() => {
										toggleInstrumentSelection(instrument);
									}}
									className={isSelected ? styles.isSelected : null}
								>
									{/* <span>{instrument.symbol}</span> */}
									<span>{instrument.exch_seg === 'NFO' || instrument.exch_seg === 'MCX' ? instrument.symbol : instrument.name}</span>
									<span />
								</button>
							</li>
						);
					})}
				</ul>
			)}

			<div className={styles.searchListFtr}>
				<div>
					<Button variant="tertiary" onClick={cancelSearch}>
						Cancel
					</Button>
					<Button
						variant="primary"
						onClick={async () => {
							setIsAddingOpWip(true);
							const isAddOpSuccessfull = await addToWatchlist(
								Object.keys(selectedInstrumentsObj).map((token) => selectedInstrumentsObj[token]),
							).finally(() => setIsAddingOpWip(false));
							isAddOpSuccessfull && cancelSearch(); //effectively takes us back to watchlist page
						}}
						isDisabled={Object.keys(selectedInstrumentsObj).length < 1}
						isWip={isAddingOpWip}
						wipText="Adding"
					>
						Add to Watchlist
					</Button>
				</div>
			</div>
			{isSearchWip && <Loading note="Searching" />}
		</>
	);
}
